use Temporal\Tests\Test262\Assert;
$plainYearMonth = new \Temporal\Spec\PlainYearMonth(2024, 12, 'iso8601', 26);
$result = $plainYearMonth->toLocaleString('en-u-ca-iso8601', ['timeZone' => 'UTC']);
Assert::assertTrue(str_contains($result, '2024'), "PlainYearMonth formatted with no options {$result} should include year");
Assert::assertTrue(str_contains($result, '12') || str_contains($result, 'Dec'), "PlainYearMonth formatted with no options {$result} should include month");
Assert::assertTrue(!str_contains($result, '26'), "PlainYearMonth formatted with no options {$result} should not include reference day");
Assert::assertTrue(!str_contains($result, '00'), "PlainYearMonth formatted with no options {$result} should not include hour, minute, second");
